import json

baseline = json.load(open('baseline-packages.json'))
after = json.load(open('after-cpm-packages.json'))

def extract(data):
    result = {}
    for p in data['projects']:
        proj = p['path'].split('/')[-1]
        for fw in p.get('frameworks', []):
            tfm = fw['framework']
            for pkg in fw.get('topLevelPackages', []):
                key = (proj, tfm, pkg['id'])
                result[key] = (pkg['requestedVersion'], pkg['resolvedVersion'])
    return result

b = extract(baseline)
a = extract(after)

changes = []
unchanged = []
for key in sorted(set(list(b.keys()) + list(a.keys()))):
    proj, tfm, pkg = key
    bv = b.get(key, (None, None))
    av = a.get(key, (None, None))
    if bv[1] != av[1] if av else True:
        changes.append((proj, tfm, pkg, bv[1], av[1] if av else 'REMOVED'))
    elif key not in b:
        changes.append((proj, tfm, pkg, 'ADDED', av[1]))
    else:
        unchanged.append((proj, tfm, pkg, av[1] if av else bv[1]))

if changes:
    print('CHANGES:')
    print(f'{\"Project\":<18} {\"TFM\":<10} {\"Package\":<50} {\"Before\":<12} {\"After\":<12}')
    print('-' * 102)
    for c in changes:
        print(f'{c[0]:<18} {c[1]:<10} {c[2]:<50} {c[3]:<12} {c[4]:<12}')
    print()

print('UNCHANGED:')
print(f'{\"Project\":<18} {\"TFM\":<10} {\"Package\":<50} {\"Version\":<12}')
print('-' * 90)
for u in unchanged:
    print(f'{u[0]:<18} {u[1]:<10} {u[2]:<50} {u[3]:<12}')
"", "description": "Compare baseline vs post-CPM", "initial_wait": 30}

